-- ─── 1. Diabète Maroc — alimentation ───────────────────────────────
INSERT INTO articles (slug, title_fr, excerpt_fr, content_fr, category, reading_time_min, status, date_published)
VALUES (
  'diabete-alimentation-maroc-produits-a-eviter',
  'Diabète au Maroc : 8 produits à éviter dans les rayons',
  'Le diabète touche plus de 2,7 millions de Marocains. Voici les produits du quotidien qui font le plus grimper la glycémie — et leurs alternatives.',
  E'## Le diabète au Maroc en chiffres\n\nSelon les dernières données du **Ministère de la Santé marocain et de l''OMS**, le diabète de type 2 touche aujourd''hui **environ 12% des adultes au Maroc** — soit plus de 2,7 millions de personnes. Le chiffre a doublé en 15 ans. La cause principale : l''industrialisation rapide de l''alimentation, la sédentarité urbaine et la consommation massive de sucre.\n\nUn point essentiel : **on peut considérablement améliorer sa glycémie en éliminant 5-10 produits du quotidien**, sans changer radicalement son alimentation. Voici les principaux.\n\n## 1. Pain industriel blanc (baguettes longue conservation)\n\nIndice glycémique (IG) : **70-85** — équivalent à du sucre pur. Tu manges 100g, tu fais un pic de glycémie qui force le pancréas à produire un shot d''insuline. Répété 3 fois par jour = épuisement progressif des cellules bêta.\n\n**Alternative** : khobz dyal dar maison ou pain complet (Tafarnout, pain de campagne). IG **40-55**.\n\n## 2. Boissons sucrées (sodas, Ice Tea, Hawai, Pulpy, sirops)\n\nUne canette de Coca = 35g de sucre = **8.5 morceaux**. Le pire : pas de fibres pour ralentir l''absorption. Pic glycémique dans les 15 minutes.\n\n**Alternative** : eau infusée à la menthe + citron, eau gazeuse + tranche de citron, kéfir maison (peu sucré).\n\n## 3. Jus de fruits "100% pur jus" (Marrakech, Valencia, Tropicana)\n\nMême "sans sucre ajouté", un jus d''orange industriel contient **10g de sucre / 100ml**, sans les fibres de l''orange entière qui ralentiraient l''absorption. C''est aussi mauvais qu''un soda pour la glycémie.\n\n**Alternative** : mange l''orange entière. Si tu veux un jus, presse-le toi-même et bois-le immédiatement avec quelques quartiers d''orange en plus pour les fibres.\n\n## 4. Céréales du petit-déj sucrées (Chocapic, Coco Pops, Frosties)\n\nUn bol enfant (40g) = **12-16g de sucre + IG élevé**. Combiné au lait sucré, c''est une bombe glycémique en début de journée.\n\n**Alternative** : **flocons d''avoine nature** (IG 55) + cannelle + 1 datte coupée. Tu tiens jusqu''à midi sans coup de fatigue. 15 DH le paquet de 500g qui dure 3 semaines.\n\n## 5. Riz blanc précuit (sachet 10 min, en grande surface)\n\nLe riz blanc précuit a un IG **72-79**. Le riz basmati classique : 50-58. Le riz complet : 50.\n\n**Alternative** : passe au **riz basmati ou riz complet**. La différence de prix est marginale, le bénéfice glycémique est énorme.\n\n## 6. Dattes en grande quantité\n\nSurprise : les dattes sont riches en sucre (60-70g / 100g). Saines en petite quantité (2-3 dattes Medjoul = 70 kcal) mais en gros volumes à l''iftar, elles peuvent provoquer un pic glycémique majeur.\n\n**Recommandation diabétique** : **maximum 3 dattes par jour**, toujours accompagnées d''une source de protéines (amandes, fromage, yaourt) qui ralentit l''absorption.\n\n## 7. Confitures industrielles (Aicha, Bonne Maman)\n\nUne confiture standard = **60-65% de sucre**. Une cuillère à soupe = 3 morceaux de sucre. Le matin sur du pain blanc = double pic glycémique.\n\n**Alternative** : confitures "sans sucre ajouté" (édulcorées au stévia), ou banane écrasée + cannelle, ou purée d''amandes.\n\n## 8. Pâtisseries marocaines industrielles (msemen surgelés, chebbakia, halwa chamia en barre)\n\nLa version industrielle de ces produits combine **huile palme + sucre + farine raffinée** : triple peine pour la glycémie. La version maison de Mama est bien plus saine (meilleure huile, moins de sucre).\n\n**Alternative** : limite à 1-2 pièces par occasion, idéalement maison.\n\n## La règle simple à retenir\n\nAvant chaque achat, scanne le produit sur Bayen et regarde le champ **sucres / 100g**. Si > 15g, demande-toi si c''est nécessaire. Pour le diabétique :\n\n- < 5g/100g : OK quotidien\n- 5-15g/100g : occasionnel\n- > 15g/100g : exceptionnel\n\n> Si tu es diabétique ou pré-diabétique, demande à ton médecin ou diététicien un plan personnalisé. Cet article est informatif, pas un remplacement d''un suivi médical.\n\n[Scanne ton placard maintenant](/scan) — tu vas identifier 3-5 produits problématiques en 10 minutes.',
  'bien-etre',
  6,
  'published',
  NOW() - INTERVAL '1 hour'
) ON CONFLICT (slug) DO UPDATE SET title_fr=EXCLUDED.title_fr, excerpt_fr=EXCLUDED.excerpt_fr, content_fr=EXCLUDED.content_fr, status=EXCLUDED.status, date_published=EXCLUDED.date_published;

-- ─── 2. Huile de palme au Maroc ────────────────────────────────────
INSERT INTO articles (slug, title_fr, excerpt_fr, content_fr, category, reading_time_min, status, date_published)
VALUES (
  'huile-palme-maroc-produits-impact-sante',
  'Huile de palme au Maroc : où elle se cache et pourquoi la limiter',
  'Elle est partout : biscuits, pâtes à tartiner, plats préparés, margarines. Voici comment la repérer et les marques marocaines qui s''en passent.',
  E'## Pourquoi l''huile de palme pose problème\n\nL''huile de palme représente **35% de la production mondiale d''huiles végétales**. Au Maroc, on la retrouve dans la quasi-totalité des produits transformés industriels — souvent cachée derrière des appellations vagues comme "huile végétale" sur l''étiquette.\n\nDeux problèmes principaux :\n\n### 1. Côté santé\nL''huile de palme est composée à **50% d''acides gras saturés**. Une consommation régulière augmente le LDL ("mauvais" cholestérol) et favorise l''athérosclérose. L''**EFSA** (Autorité européenne de sécurité des aliments) a aussi pointé en 2016 la présence de **contaminants 3-MCPD et glycidyl** générés lors du raffinage à haute température — potentiellement cancérigènes.\n\n### 2. Côté environnement\n90% de la production mondiale vient d''Indonésie et Malaisie, où elle est responsable de **déforestation massive** de forêts primaires (habitat de l''orang-outan, du tigre de Sumatra).\n\n## Où elle se cache au Maroc\n\nAttention aux étiquettes : **"huile végétale" sans précision = quasi-toujours huile de palme** (la moins chère). Les industriels marocains et internationaux l''utilisent massivement.\n\n### Catégories les plus concernées\n\n- **Biscuits industriels** : Petit Lu, Prince LU, Oreo, Speculoos Lotus, Belvita, palmiers\n- **Pâtes à tartiner** : Nutella, Cocoba, Suprella, Crema, certaines pâtes locales\n- **Plats préparés surgelés** : pizzas, lasagnes, samosas industriels, briouates surgelées\n- **Margarines** : Tournesol, Astra Fluide, Beaufort, certaines tartines\n- **Viennoiseries industrielles** : croissants/pains au chocolat sous plastique\n- **Soupes en sachet** : Maggi, Knorr (variants)\n- **Glaces industrielles** : Magnum, certains Cornetto, glaces "économiques"\n- **Chips et apéritifs frits** : certaines marques (vérifie au cas par cas)\n\n## Comment l''identifier sur l''étiquette\n\nLes industriels jouent sur la sémantique pour éviter le mot "palme" qui inquiète. Cherche dans la liste d''ingrédients :\n\n- "huile de palme" / "graisse de palme" / "stéarine de palme"\n- "huile de palmiste" (extraite du noyau du palmier)\n- "huile végétale" sans précision = **drapeau rouge**, demande-toi pourquoi\n- "matières grasses végétales" / "graisses végétales"\n- "RBD palm oil" / "palm fruit oil"\n\n## Marques marocaines qui s''en passent (ou affichent clairement)\n\nQuelques marques locales ont fait le choix de l''éviter ou de transparenter :\n\n- **Dari** sur certains produits (vérifier ligne par ligne)\n- **Aicha** sur les confitures (huile de tournesol majoritaire)\n- **Sidi Ali** (n''utilise pas d''huile dans l''eau, évidemment)\n- **Marques bio importées** Naturalia, Carrefour Bio (mais cher)\n\n## Alternatives en cuisine\n\nQuand tu cuisines toi-même, remplace facilement :\n\n- **Cuisson** : huile d''olive du Maroc (premier choix), huile de tournesol (neutre), huile de colza\n- **Pâtisseries** : beurre, huile de coco, purée de noix\n- **Tartinables** : beurre de cacahuète 100% (sans huile ajoutée), purée d''amande, purée de noisettes\n\n## La règle Bayen sur l''huile de palme\n\nDans notre score, l''huile de palme contribue indirectement :\n- Augmente les **acides gras saturés** → pénalité Nutri-Score\n- Présence souvent dans des produits **NOVA 4** (ultra-transformés) → pénalité NOVA\n- Pas d''additif spécifique mais corrélé à d''autres additifs (émulsifiants, conservateurs)\n\n[Scanne ton placard](/scan) en cherchant "huile de palme" dans la liste d''ingrédients. Tu seras surpris.\n\n> Comme toujours : le pire n''est pas un peu d''huile de palme dans un produit occasionnel. C''est de la consommer 5 fois par jour sans s''en rendre compte.',
  'guides',
  5,
  'published',
  NOW() - INTERVAL '2 days'
) ON CONFLICT (slug) DO UPDATE SET title_fr=EXCLUDED.title_fr, excerpt_fr=EXCLUDED.excerpt_fr, content_fr=EXCLUDED.content_fr, status=EXCLUDED.status, date_published=EXCLUDED.date_published;

-- ─── 3. Yaourts marocains comparatif ───────────────────────────────
INSERT INTO articles (slug, title_fr, excerpt_fr, content_fr, category, reading_time_min, status, date_published)
VALUES (
  'meilleurs-yaourts-maroc-comparatif',
  'Quel est le meilleur yaourt au Maroc ? Comparatif Jaouda, Centrale, Yawmy',
  'On a passé au scanner Bayen les yaourts les plus vendus au Maroc. Voici le verdict, marque par marque, du nature au aromatisé.',
  E'## Le yaourt : meilleur ami de la santé… ou bombe sucrée déguisée ?\n\nLe yaourt fait partie des produits laitiers les plus consommés au Maroc — entre 8 et 12 kg par habitant par an selon les chiffres FENAGRI. Côté nutrition, c''est une excellente source de **protéines** (5-7g / 100g), de **calcium** et de **probiotiques**. Mais attention : entre un yaourt nature et un yaourt aromatisé "fraise enfants", la différence peut être de **18g de sucre par pot**.\n\nVoici notre comparatif des principales marques marocaines, basé sur les données scannées sur Bayen et leurs étiquettes officielles.\n\n## Top yaourts nature (les meilleurs)\n\n### 🥇 Jaouda nature classique\n- **Sucres** : 4.5g / 100g (sucres naturellement présents dans le lait, pas d''ajout)\n- **Protéines** : 4.8g / 100g\n- **Matières grasses** : 3.5g / 100g\n- **Additifs** : 0\n- **Score Bayen** : excellent\n\nLe choix de référence. Polyvalent en cuisine, idéal pour les enfants.\n\n### 🥈 Centrale Danone nature\n- **Sucres** : 4.5g / 100g\n- **Protéines** : 4.2g / 100g\n- **Additifs** : 0\n- **Score Bayen** : excellent\n\nÉquivalent à Jaouda. Choisis selon ton fournisseur de quartier.\n\n### 🥉 Yawmy nature\n- **Sucres** : 4.7g / 100g\n- **Protéines** : 4.5g / 100g\n- **Additifs** : 0\n- **Score Bayen** : excellent\n\nMoins distribué mais qualité similaire.\n\n## Yaourts aromatisés (à consommer occasionnellement)\n\n### Jaouda aux fruits (fraise, vanille, banane)\n- **Sucres** : 13-15g / 100g (soit 3 morceaux de sucre par pot de 125g)\n- **Additifs** : arômes, parfois E440 (pectines), gomme guar\n- **Score Bayen** : médiocre\n\nLes fruits annoncés sont souvent < 5% du produit. Le reste = sucre + arôme.\n\n### Activia (Centrale Danone)\n- **Sucres** : 12-14g / 100g\n- **Protéines** : 3.8g / 100g\n- **Probiotiques** : Bifidus ActiRegularis (marque déposée, effet santé limité)\n- **Score Bayen** : médiocre\n\nLe marketing "transit" est vendu à prix premium pour un produit aussi sucré que la concurrence.\n\n### Yaourts "enfants" (Petits Filous, Kid Jaouda, Mickey, etc.)\n- **Sucres** : 15-18g / 100g (le pire)\n- **Additifs** : colorants, arômes\n- **Score Bayen** : mauvais\n\n**Évite ces yaourts pour les enfants.** Ils contiennent plus de sucre qu''un yaourt adulte aromatisé, sous prétexte de "petit format". Un Petit Filou 60g = 9g de sucre = 2 morceaux.\n\n## Yaourts à boire (alerte sucre)\n\n### Yawmy à boire, Danao, Jus + Lait\n- **Sucres** : 10-13g / 100g\n- **Format** : 200ml → 20-26g de sucre par bouteille\n- **Score Bayen** : médiocre à mauvais\n\nC''est essentiellement du **lait sucré aromatisé**, pas un produit santé.\n\n## Yaourts grecs et hauts en protéines\n\n### Jaouda Grec / Activia Protéines\n- **Sucres** : 5-8g / 100g (nature) ou 13-16g (aromatisés)\n- **Protéines** : 7-10g / 100g (vs 4-5g classique)\n- **Score Bayen** : bon en version nature\n\nIdéal pour les sportifs ou les personnes cherchant à augmenter leur apport en protéines.\n\n## Le hack : faire son yaourt sucré soi-même\n\nPlutôt que d''acheter du Jaouda fraise (15g de sucre + arômes + colorants), achète du **Jaouda nature** et ajoute :\n\n- 1 cuillère à café de miel (4g de sucre vs 15g)\n- 3-4 morceaux de fraise fraîche ou abricot sec\n- 1 pincée de cannelle ou vanille\n\nRésultat : **2× moins de sucre, zéro additif, vrai fruit**. Coût équivalent.\n\n## La bonne habitude\n\n[Scanne tes yaourts](/scan) avant de remplir le chariot. Pour 80% des consommateurs marocains, passer du yaourt aromatisé au yaourt nature + fruit représente la **réduction de sucre la plus simple et la plus impactante** au quotidien.',
  'guides',
  6,
  'published',
  NOW() - INTERVAL '3 days'
) ON CONFLICT (slug) DO UPDATE SET title_fr=EXCLUDED.title_fr, excerpt_fr=EXCLUDED.excerpt_fr, content_fr=EXCLUDED.content_fr, status=EXCLUDED.status, date_published=EXCLUDED.date_published;

-- ─── 4. Goûters enfants sains Maroc ────────────────────────────────
INSERT INTO articles (slug, title_fr, excerpt_fr, content_fr, category, reading_time_min, status, date_published)
VALUES (
  'gouter-enfants-sain-maroc-idees',
  'Goûters sains pour enfants au Maroc : 12 idées prêtes en 2 minutes (et moins chères que les biscuits)',
  'Stop aux Prince, Choco-Prince et yaourt à boire. Voici 12 alternatives marocaines équilibrées, économiques, et que tes enfants adorent.',
  E'## Le goûter, ce moment piégé\n\nLe goûter est probablement **le repas le plus mal nourri de la journée** chez les enfants marocains. Pris à la sortie de l''école, dans la précipitation, il finit trop souvent en : Prince LU + Hawai + paquet de chips. Résultat : 50g de sucre, 4 additifs, peu de protéines, faim 30 minutes plus tard.\n\nLa bonne nouvelle : un goûter équilibré ne prend **pas plus de temps à préparer**, coûte **moins cher**, et installe les bonnes habitudes pour la vie.\n\n## La structure du goûter idéal\n\nPour bien tenir jusqu''au dîner, vise 3 composantes :\n\n1. **Glucides complexes** (pain complet, flocons d''avoine, riz, dattes)\n2. **Protéines** (fromage, œuf dur, beurre de cacahuète, yaourt nature)\n3. **Fibres / vitamines** (fruit frais ou légume cru)\n\nEn pratique : 1 part de chaque + 1 verre d''eau. Ça suffit.\n\n## 12 idées prêtes en 2 minutes\n\n### Sucrés sains\n\n**1. Pain complet + miel + amandes** — 2 tranches de pain complet (1 DH), 1 cuillère à café de miel local (1 DH), 5 amandes (1 DH). Total : **3 DH**, 250 kcal équilibrées.\n\n**2. Yaourt nature + dattes + cannelle** — 1 yaourt Jaouda nature (2 DH) + 2 dattes Medjoul écrasées (3 DH) + pincée de cannelle. Total : **5 DH**, ultra-rassasiant.\n\n**3. Banane + beurre de cacahuète 100%** — 1 banane (2 DH) + 1 cuillère à café de beurre de cacahuète pur (1 DH, sans huile ajoutée). Total : **3 DH**, parfait avant le sport.\n\n**4. Pomme + carré de chocolat noir 70%** — 1 pomme (2 DH) + 2 carrés chocolat 70% (1.5 DH). Total : **3.5 DH**, le combo équilibré.\n\n**5. Khobz dyal dar maison + huile d''olive + miel** — 1 part de khobz (gratuit, fait maison) + huile d''olive marocaine + miel. Total : **2 DH**, traditionnel et excellent.\n\n**6. Smoothie banane-lait-amande maison** — 1 banane + 200ml lait + 5 amandes mixées. **4 DH**, riche en calcium et protéines.\n\n### Salés équilibrés\n\n**7. Œuf dur + tomate cerise + pain complet** — 1 œuf (1 DH) + 5 tomates cerises (3 DH) + tranche de pain. Total : **5 DH**, hyper-protéiné.\n\n**8. Fromage frais + concombre + pain** — 30g de fromage frais (2 DH) + concombre tranché (1 DH) + pain. Total : **4 DH**.\n\n**9. Houmous maison + bâtonnets de carotte** — 1 cuillère à soupe d''houmous (préparé d''avance) + carottes coupées en bâtonnets. Total : **2-3 DH** par portion, l''enfant adore tremper.\n\n### Apéro/snack maison\n\n**10. Pois chiches grillés aux épices** — Pois chiches secs trempés + grillés au four avec paprika/cumin/huile d''olive. **5 DH pour 500g** qui dure 1 semaine. Croquant, protéiné, alternative parfaite aux chips.\n\n**11. Mélange "trail mix" maison** — Amandes + raisins secs + cacahuètes nature + petits morceaux de chocolat noir. Conservation 1 mois dans un bocal. **20 DH pour 500g**.\n\n**12. Crêpe complète maison** — 1 crêpe avec un peu de sucre + cannelle ou compote sans sucre ajouté. Préparée à l''avance le dimanche pour toute la semaine.\n\n## Comparatif coût/qualité vs goûter industriel\n\n| Option | Coût | Sucres | Additifs | Score Bayen |\n|---|---|---|---|---|\n| Prince LU + Hawai | 12 DH | 45g | 8 | Mauvais |\n| Yaourt + dattes | 5 DH | 12g (naturel) | 0 | Excellent |\n| Pain + miel + amandes | 3 DH | 5g | 0 | Excellent |\n\n**Tu paies plus cher pour un goûter pire**. C''est ironique mais bien réel.\n\n## La règle des "vrais aliments"\n\nDit autrement : si tu peux nommer chaque ingrédient et qu''il existe dans la nature, c''est probablement un bon goûter. Si tu vois "E471, sirop de glucose, arôme, gomme xanthane, conservateur" sur l''étiquette, repose le paquet.\n\n[Scanne 3 goûters industriels que tu achètes habituellement](/scan). Note les scores. Tu as ta réponse en 3 minutes.\n\n## Astuce parent débordé\n\nLe dimanche soir, prépare en 15 minutes :\n- 1 boîte de pois chiches grillés (semaine entière)\n- 1 bocal de trail mix\n- 5 oeufs durs\n- 1 saladier de carottes et concombres tranchés\n\nLa semaine devient facile.',
  'habitudes',
  6,
  'published',
  NOW() - INTERVAL '4 days'
) ON CONFLICT (slug) DO UPDATE SET title_fr=EXCLUDED.title_fr, excerpt_fr=EXCLUDED.excerpt_fr, content_fr=EXCLUDED.content_fr, status=EXCLUDED.status, date_published=EXCLUDED.date_published;

-- ─── 5. Étiquettes en arabe ────────────────────────────────────────
INSERT INTO articles (slug, title_fr, excerpt_fr, content_fr, category, reading_time_min, status, date_published)
VALUES (
  'lire-etiquette-arabe-maroc-vocabulaire',
  'Lire une étiquette en arabe au Maroc : le vocabulaire de survie',
  'Beaucoup de produits marocains affichent leurs ingrédients uniquement en arabe. Voici les 30 mots à connaître pour décoder n''importe quelle étiquette.',
  E'## Le problème spécifique au Maroc\n\nContrairement aux pays européens où l''étiquetage en français est obligatoire, **au Maroc une grande partie des produits — notamment ceux importés du Moyen-Orient ou de Turquie — affichent leurs ingrédients en arabe uniquement**. Pour les francophones, c''est un casse-tête.\n\nVoici un mini-glossaire pour **identifier en 30 secondes les composants problématiques** sans avoir besoin de traduire mot par mot.\n\n## Les 30 mots à connaître\n\n### Catégories d''ingrédients\n\n| Arabe | Phonétique | Français |\n|---|---|---|\n| المكونات | al-moukawwinat | Ingrédients |\n| القيم الغذائية | al-qiyam al-ghidha''iya | Valeurs nutritionnelles |\n| لكل 100 غرام | li-koul 100 ghram | Pour 100g |\n| الحصة | al-hissa | La portion |\n| تحتوي على | tahtawi 3ala | Contient |\n| قد يحتوي آثار | qad yahtawi athar | Peut contenir des traces |\n\n### Sucres (à surveiller en priorité)\n\n| Arabe | Phonétique | Français |\n|---|---|---|\n| السكر | as-soukkar | Sucre |\n| سكر مضاف | soukkar moudaf | Sucre ajouté |\n| شراب الجلوكوز | sharab al-glucose | Sirop de glucose |\n| فركتوز | fructoz | Fructose |\n| دكستروز | dextroz | Dextrose |\n| شراب الذرة | sharab adh-dhoura | Sirop de maïs |\n\n### Matières grasses\n\n| Arabe | Phonétique | Français |\n|---|---|---|\n| الدهون | ad-douhoun | Matières grasses |\n| دهون مشبعة | douhoun moushabba''a | Graisses saturées |\n| زيت النخيل | zayt an-nakhil | Huile de palme (rouge) |\n| زيت نباتي | zayt nabati | Huile végétale (souvent palme) |\n| زيت الزيتون | zayt az-zaytoun | Huile d''olive |\n| زيت دوار الشمس | zayt dawwar ash-shams | Huile de tournesol |\n\n### Allergènes courants\n\n| Arabe | Phonétique | Français |\n|---|---|---|\n| الحليب | al-halib | Lait |\n| البيض | al-bayd | Œufs |\n| القمح | al-qamh | Blé |\n| الغلوتين | al-gluten | Gluten |\n| فول الصويا | foul as-soya | Soja |\n| المكسرات | al-moukassarat | Fruits à coque |\n| الفول السوداني | al-foul as-soudani | Arachide |\n| السمسم | as-simsim | Sésame |\n\n### Termes problématiques (drapeaux rouges)\n\n| Arabe | Phonétique | Français |\n|---|---|---|\n| مواد حافظة | mawad hafiza | Conservateurs |\n| مواد ملونة | mawad moulawwina | Colorants |\n| نكهات صناعية | nakhat sina''iya | Arômes artificiels |\n| محسن للنكهة | mouhassin lin-nakha | Exhausteur de goût |\n| محلي صناعي | mouhalli sina''i | Édulcorant artificiel |\n\n## Les codes E-xxx sont universels\n\nBonne nouvelle : **les additifs E-xxx s''écrivent pareil partout** (E102, E150, E322…). Si tu vois ces codes même au milieu d''une étiquette en arabe, tu peux les chercher directement sur [notre base d''additifs](/additifs).\n\nExemple : "E951 — أسبارتام" = aspartame (édulcorant à éviter).\n\n## La méthode de scan rapide\n\nPour décoder une étiquette en arabe en 30 secondes :\n\n1. **Cherche les chiffres** : les valeurs pour 100g sont en chiffres arabo-indiens (٠١٢٣٤٥٦٧٨٩) ou occidentaux. Repère le sucre (السكر).\n2. **Cherche les codes E** : ils sautent aux yeux dans la liste d''ingrédients.\n3. **Cherche زيت النخيل** (huile de palme) : 3 caractères courts, faciles à repérer.\n4. **Scanne le code-barres sur Bayen** : on récupère les données et on traduit pour toi.\n\n## Astuce : le code-barres est ton meilleur ami\n\nLa quasi-totalité des produits importés au Maroc ont un code-barres EAN-13. Le préfixe du code-barres indique souvent le pays d''origine :\n\n- **611** = Maroc\n- **626** = Égypte\n- **628** = Arabie Saoudite\n- **869** = Turquie\n- **890** = Inde\n- **40-44** = Allemagne\n- **30-37** = France\n\nUtile pour identifier d''où vient un produit, surtout pour les marques inconnues.\n\n## L''étiquetage marocain devrait évoluer\n\nLa loi 28-07 sur la sécurité sanitaire des produits alimentaires impose un étiquetage en arabe ET dans une autre langue (français généralement). En pratique, l''application est inégale, surtout sur les produits importés du Golfe et de Turquie en grandes surfaces.\n\n**Si tu repères un produit sans étiquetage francophone clair, signale-le** à l''ONSSA via leur portail ou via une association de consommateurs. Plus on signale, plus la pression s''exerce.\n\n[Scanne tes produits arabes inconnus](/scan) — la base Bayen contient déjà les traductions pour 2000+ produits indexés.',
  'guides',
  6,
  'published',
  NOW() - INTERVAL '5 days'
) ON CONFLICT (slug) DO UPDATE SET title_fr=EXCLUDED.title_fr, excerpt_fr=EXCLUDED.excerpt_fr, content_fr=EXCLUDED.content_fr, status=EXCLUDED.status, date_published=EXCLUDED.date_published;

-- ─── 6. Thé marocain et sucre ──────────────────────────────────────
INSERT INTO articles (slug, title_fr, excerpt_fr, content_fr, category, reading_time_min, status, date_published)
VALUES (
  'the-marocain-sucre-reduire-sans-perdre-tradition',
  'Thé à la menthe : réduire le sucre sans perdre le plaisir',
  'Le Marocain moyen consomme 36 kg de sucre par an — l''équivalent de 400 morceaux par mois. Le thé en est un coupable principal. Voici comment réduire sans renier la tradition.',
  E'## Combien de sucre dans ton thé ?\n\nLe **thé à la menthe** est sans doute la boisson la plus emblématique de la culture marocaine. Mais quand on regarde les chiffres, c''est aussi **la principale source quotidienne de sucre** pour beaucoup de familles.\n\n### Une théière marocaine standard (50cl, 4 verres) :\n- **3 morceaux de sucre par verre** en moyenne (recette familiale typique)\n- **12 morceaux par théière** = 48g de sucre\n- **2 théières par jour** = **96g de sucre = 24 morceaux**\n\nL''OMS recommande **maximum 25g (6 morceaux) de sucres ajoutés par jour**. Une seule théière dépasse déjà cette limite quotidienne.\n\nEt on n''a pas encore parlé des chebbakia, du msemen ou du jus à côté.\n\n## Pourquoi c''est un problème\n\n**Le sucre dans le thé n''a pas la même perception que le sucre dans un soda** : on l''accepte comme "normal", "traditionnel", "amical". Mais biologiquement, c''est exactement le même impact :\n\n- Pic glycémique → insuline → stockage en graisse + faim 1h après\n- Sur le long terme : risque diabète type 2, surpoids, gras viscéral\n- Impact dentaire majeur (le sucre + chaleur amplifie l''érosion de l''émail)\n- Effet addictif (dopamine = envie de plus)\n\n## La méthode du sevrage progressif (3 semaines)\n\nLa pire idée : passer du thé sucré au thé amer du jour au lendemain. Tu vas détester, tu vas craquer.\n\nLa méthode qui marche : **réduire de 0.5 morceau par théière chaque semaine**.\n\n### Semaine 1 : -10%\n- Théière habituelle (12 morceaux) → 10-11 morceaux\n- Personne ne le sentira\n\n### Semaine 2 : -25%\n- 8-9 morceaux par théière\n- Tes papilles s''adaptent. C''est encore très sucré pour quelqu''un d''habitué au "thé européen".\n\n### Semaine 3 : -50%\n- 6 morceaux par théière (1.5 par verre)\n- Le thé révèle des saveurs que tu ne percevais plus : fraîcheur de la menthe, complexité du thé vert, arôme de l''absinthe ou de la verveine.\n\n### Semaine 4+ : trouve ton sweet spot\n- 4-6 morceaux selon ton goût\n- Tu auras divisé ton apport en sucre quotidien lié au thé par 2 ou 3, sans renoncer\n\n## 5 astuces de "compensation gustative"\n\nLe sucre cache certaines saveurs. En réduisant, profite-en pour enrichir le profil aromatique :\n\n### 1. Plus de menthe fraîche\nDouble la dose de menthe : son intensité aromatique compense la perception de "fade" qu''on associe parfois au moins sucré.\n\n### 2. Ajoute une ou deux variantes\n- Verveine fraîche (لويزا) — douceur naturelle\n- Sauge (سالمية) — corsée et chaude\n- Absinthe (شيبة) — légèrement amère, complémentaire\n- Fleur d''oranger (en quelques gouttes)\n- Cardamome (1 graine concassée)\n\n### 3. Investis dans un meilleur thé\nLe **thé vert Gunpowder de qualité supérieure** (35-50 DH les 250g vs 15-20 DH le standard) a une amertume plus noble et plus de saveurs subtiles. Quand tu réduis le sucre, la qualité du thé compte plus.\n\n### 4. Cuisson plus courte\nMoins tu fais bouillir le thé, moins il extrait de tanins amers. **Première extraction 30 secondes, deuxième 2-3 minutes** suffisent. Beaucoup font durer 5+ minutes, ce qui force à compenser au sucre.\n\n### 5. Eau chaude, pas bouillante\nLe thé vert s''extrait mieux à **80°C** qu''à 100°C. Plus doux, moins astringent. Stop le thé après une seule ébullition.\n\n## Et pour les enfants ?\n\nNos parents nous habituent au thé sucré dès 4-5 ans. Habitude culturelle, mais pas nécessairement saine. **Quelques principes** :\n\n- **Pas de thé avant 6 ans** (excitant + dents)\n- **Versions très diluées** entre 6 et 10 ans (1/3 thé, 2/3 eau chaude)\n- **Sans sucre ajouté** pour les enfants : la menthe + verveine + une datte écrasée suffisent\n\nC''est l''occasion de faire goûter le **thé blanc** ou **infusions** (verveine, camomille, fleur d''oranger pures) qui ont leur place dans la tradition marocaine.\n\n## Ce que tu gagnes\n\nEn 1 mois de sevrage progressif :\n\n- **24 → 8 morceaux de sucre par jour** liés au thé (-67%)\n- Sur 1 an : **5,8 kg de sucre économisés** en équivalent calorique\n- Énergie plus stable l''après-midi (pas de pic-creux)\n- Papilles plus fines (tu perçois mieux le goût des aliments)\n- Estomac moins ballonné\n\n## La culture ne disparaît pas, elle évolue\n\nLes générations marocaines des années 1960-70 buvaient beaucoup moins sucré qu''aujourd''hui (le sucre était plus rare). Réduire, c''est revenir à un thé plus proche de celui de nos grands-parents — pas le moderniser.\n\n[Scanne ton paquet de thé et ton sucre](/scan) pour avoir les valeurs nutritionnelles précises. Et partage la méthode avec les invités : "On essaie un thé moins sucré ce mois-ci, dis-moi ce que tu en penses."',
  'habitudes',
  7,
  'published',
  NOW() - INTERVAL '6 days'
) ON CONFLICT (slug) DO UPDATE SET title_fr=EXCLUDED.title_fr, excerpt_fr=EXCLUDED.excerpt_fr, content_fr=EXCLUDED.content_fr, status=EXCLUDED.status, date_published=EXCLUDED.date_published;

-- ─── 7. Nutrition sportif Maroc ────────────────────────────────────
INSERT INTO articles (slug, title_fr, excerpt_fr, content_fr, category, reading_time_min, status, date_published)
VALUES (
  'nutrition-sport-maroc-produits-locaux',
  'Sport et nutrition au Maroc : que manger avec des produits 100% locaux',
  'Pas besoin de poudres importées à 400 DH. La cuisine marocaine traditionnelle est une mine d''or pour les sportifs. Voici comment composer ses repas selon les efforts.',
  E'## Le marketing fitness n''est pas pour toi\n\nIl suffit d''entrer dans n''importe quel magasin de complément alimentaire au Maroc : Whey Protein à 800 DH, BCAA à 350 DH, créatine à 300 DH, "pré-workout" à 400 DH. La majorité de ces produits sont **inutiles pour 90% des sportifs amateurs**, qui s''entraînent 3-4 fois par semaine.\n\nLa vérité scientifique : **les nutriments essentiels au sportif amateur (et même intermédiaire) se trouvent dans la cuisine marocaine traditionnelle**, à un coût ridicule. Voici comment composer.\n\n## Les 4 macronutriments du sportif\n\n### 1. Protéines (réparation musculaire)\n**Besoin** : 1.2-1.8g par kg de poids corporel par jour pour un sportif amateur. Un homme de 75 kg = ~100g de protéines/jour. Une femme de 60 kg = ~80g.\n\n**Sources locales bon marché** :\n- **Œufs** (6g de protéines / œuf, 1.50 DH pièce)\n- **Poulet** (25g / 100g, 35-45 DH / kg)\n- **Sardines fraîches** (25g / 100g, 15-25 DH / kg — pic protéines + oméga-3)\n- **Lentilles** (24g / 100g sec, 20 DH / kg — l''option vegan)\n- **Pois chiches** (19g / 100g, 12-15 DH / kg)\n- **Fromage frais / Lben** (15-20g / 100g)\n- **Yaourt grec Jaouda** (7g / 100g, ~5 DH le pot)\n\nUn plat de **lentilles + œufs durs + pain complet** = 40g de protéines pour 10-12 DH. La whey à 800 DH coûte 10 DH par dose.\n\n### 2. Glucides (énergie)\n**Besoin** : 4-7g par kg/jour selon intensité. Privilégier les glucides complexes (IG bas/moyen).\n\n**Sources locales** :\n- **Couscous complet** (75g / 100g, 8 DH / kg)\n- **Pain complet / Khobz dyal dar maison** (50g / 100g)\n- **Pommes de terre** (15g / 100g, 5 DH / kg)\n- **Riz basmati** (78g / 100g, 18 DH / kg)\n- **Dattes** (75g / 100g — idéal avant effort, 30 DH / kg pour Medjoul)\n- **Pâtes complètes** (70g / 100g)\n\n### 3. Lipides (hormones, vitamines liposolubles)\n**Besoin** : 25-30% des calories totales, en privilégiant les bonnes graisses.\n\n**Sources locales d''excellence** :\n- **Huile d''olive marocaine** (richesse en oméga-9, polyphénols antioxydants) — 50-80 DH le litre\n- **Amandes** (50g de bonnes graisses / 100g, riches en magnésium pour les muscles)\n- **Noix** (oméga-3 — anti-inflammatoire après l''effort)\n- **Sardines à l''huile** (oméga-3 + protéines)\n- **Amlou** (purée d''amandes-argan-miel, traditionnel souss) — calorique mais excellent\n- **Avocat** (rare au Maroc mais dispo en saison)\n\n### 4. Micronutriments (vitamines, minéraux)\nL''alimentation marocaine traditionnelle est très riche en :\n- **Vitamine C** : oranges, citrons, poivrons, persil, menthe\n- **Magnésium** : amandes, sésame (msemen au sésame), légumes verts\n- **Potassium** : dattes, bananes, pommes de terre\n- **Fer** : viande rouge, lentilles, épinards, dattes\n- **Calcium** : lait, yaourt, sardines (avec arêtes), amandes\n\n## Plan d''alimentation selon l''effort\n\n### Sport léger (3-4 séances / semaine de 45-60 min)\nMaintien d''une alimentation marocaine équilibrée, sans complément. Exemple journée type :\n\n- **Petit-déj** : khobz dyal dar + 2 œufs + olives + thé peu sucré\n- **Déjeuner** : tajine de poulet aux légumes + couscous complet + salade\n- **Goûter** : yaourt nature + dattes + amandes\n- **Pré-entraînement** (30 min avant) : 2 dattes + verre d''eau\n- **Dîner** : harira complète + 1 morceau de pain + fruit\n\n### Sport intensif (5-6 séances / semaine ou prépa compétition)\n- Augmenter les protéines : viande/poisson à chaque repas + collations protéinées\n- **Pré-entraînement** (1h avant) : pain complet + miel + amandes\n- **Pendant effort >90min** : dattes ou banane + eau (les "barres énergétiques" du commerce sont du sucre + huile palme + additifs)\n- **Post-entraînement** (30 min après) : combo glucides + protéines = poulet + riz basmati + tomates OU yaourt grec + flocons d''avoine + miel\n\n## Le pré-workout marocain : 2 dattes + 1 verre d''eau\n\nVraiment. Pas besoin de pré-workout à 400 DH qui contient :\n- Caféine (un café noir à 5 DH fait le même effet)\n- Bêta-alanine (le picotement marketing — utilité limitée)\n- Créatine 1g (sous-dosée pour avoir un effet, vraie dose = 5g)\n- Édulcorants + colorants + arômes artificiels\n\n**Alternative naturelle 2 DH** : 2 dattes Medjoul (sucre rapide + potassium) + 1 espresso (caféine 80mg = boost). Effet équivalent, sans additifs.\n\n## La whey, vraiment utile ?\n\nLa whey protein devient pertinente UNIQUEMENT si :\n- Tu fais 5+ séances/semaine de musculation lourde ET\n- Tu n''atteins pas tes besoins protéiques (1.6-2g/kg) avec l''alimentation classique\n\nSinon : un yaourt grec à 7 DH = 15g de protéines, soit l''équivalent d''une demi-dose de whey à 25 DH. **3× moins cher, plus rassasiant, plus complet (calcium + probiotiques).**\n\n## Hydratation\n\nLe Maroc est chaud une grande partie de l''année. Pour un sportif amateur :\n\n- **2.5 à 3.5 litres d''eau par jour** selon poids et température\n- Pendant un effort >1h : ajouter du sel (1 pincée + jus de citron = boisson isotonique maison)\n- **Évite les "boissons énergisantes"** type Red Bull/Monster — pic d''insuline + caféine + taurine non régulée\n\n## Le piège des compléments importés\n\nMéfie-toi des compléments vendus en magasin spécialisé au Maroc. Sans **contrôle ONSSA strict** sur les compléments (contrairement à la pharmacie), tu peux trouver :\n\n- Stéroïdes anabolisants masqués (souvent dans la "testo booster")\n- Stimulants interdits (DMHA, DMAA dans certains pre-workouts)\n- Dosage non conforme à l''étiquette\n- Contaminations (métaux lourds dans les whey indiennes)\n\nSi tu en prends, **achète chez un revendeur officiel** d''une marque internationale connue (MyProtein, Optimum Nutrition, etc.) et vérifie le numéro de lot.\n\n[Scanne tes compléments](/scan) — la base Bayen inclut les protéines en poudre, barres et boissons isotoniques.',
  'bien-etre',
  8,
  'published',
  NOW() - INTERVAL '7 days'
) ON CONFLICT (slug) DO UPDATE SET title_fr=EXCLUDED.title_fr, excerpt_fr=EXCLUDED.excerpt_fr, content_fr=EXCLUDED.content_fr, status=EXCLUDED.status, date_published=EXCLUDED.date_published;

COMMIT;

-- Vérif
SELECT slug, category, reading_time_min, length(content_fr) AS chars, status,
       to_char(date_published, 'YYYY-MM-DD HH24:MI') AS published
FROM articles
WHERE date_published > NOW() - INTERVAL '8 days'
ORDER BY date_published DESC;
